import { auth } from '@/lib/auth'
import { sql } from '@/lib/db'
import { DashboardHeader } from '@/components/dashboard/header'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { Plus, MoreHorizontal, Building2, Edit, MapPin, Phone, Star } from 'lucide-react'
import Link from 'next/link'

interface Depot {
    id: string
    name: string
    address: string | null
    phone: string | null
    is_main: boolean
    stock_count: number
}

async function getDepots(companyId: string): Promise<Depot[]> {
    try {
        const depots = await sql`
      SELECT
        d.*,
        COUNT(DISTINCT s.id) as stock_count
      FROM depots d
      LEFT JOIN stock s ON s.depot_id = d.id AND s.quantity > 0
      WHERE d.company_id = ${companyId}
      GROUP BY d.id
      ORDER BY d.is_main DESC, d.name
    `
        return depots as Depot[]
    } catch {
        return []
    }
}

export default async function DepotsPage() {
    const session = await auth()
    const companyId = session?.user?.companyId || ''
    const depots = await getDepots(companyId)

    return (
        <div className="flex flex-col min-h-screen">
            <DashboardHeader
                title="Dépôts"
                description="Gérez vos dépôts et entrepôts de stockage"
                actions={
                    <Button asChild>
                        <Link href="/dashboard/depots/new">
                            <Plus className="h-4 w-4 mr-2" />
                            Nouveau dépôt
                        </Link>
                    </Button>
                }
            />

            <main className="flex-1 p-4 lg:p-6 space-y-6">
                {depots.length === 0 ? (
                    <Card>
                        <CardContent className="py-12 text-center">
                            <Building2 className="h-12 w-12 mx-auto text-muted-foreground/40" />
                            <h3 className="mt-4 text-lg font-medium">Aucun dépôt</h3>
                            <p className="mt-2 text-sm text-muted-foreground">
                                Commencez par créer votre dépôt principal.
                            </p>
                            <Button className="mt-4" asChild>
                                <Link href="/dashboard/depots/new">
                                    <Plus className="h-4 w-4 mr-2" />
                                    Créer un dépôt
                                </Link>
                            </Button>
                        </CardContent>
                    </Card>
                ) : (
                    <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                        {depots.map((depot) => (
                            <Card key={depot.id} className={depot.is_main ? 'border-accent/40 bg-accent/5' : ''}>
                                <CardHeader className="pb-3">
                                    <div className="flex items-start justify-between">
                                        <div className="flex items-center gap-2">
                                            <div className="h-9 w-9 rounded-lg bg-primary/10 flex items-center justify-center">
                                                <Building2 className="h-5 w-5 text-primary" />
                                            </div>
                                            <div>
                                                <CardTitle className="text-base">{depot.name}</CardTitle>
                                                {depot.is_main && (
                                                    <Badge variant="outline" className="text-xs mt-0.5 text-accent border-accent/50 gap-1">
                                                        <Star className="h-2.5 w-2.5" />
                                                        Principal
                                                    </Badge>
                                                )}
                                            </div>
                                        </div>
                                        <DropdownMenu>
                                            <DropdownMenuTrigger asChild>
                                                <Button variant="ghost" size="icon" className="h-8 w-8">
                                                    <MoreHorizontal className="h-4 w-4" />
                                                </Button>
                                            </DropdownMenuTrigger>
                                            <DropdownMenuContent align="end">
                                                <DropdownMenuItem asChild>
                                                    <Link href={`/dashboard/depots/${depot.id}/edit`}>
                                                        <Edit className="h-4 w-4 mr-2" />
                                                        Modifier
                                                    </Link>
                                                </DropdownMenuItem>
                                                <DropdownMenuItem asChild>
                                                    <Link href={`/dashboard/stock?depot=${depot.id}`}>
                                                        <Building2 className="h-4 w-4 mr-2" />
                                                        Voir le stock
                                                    </Link>
                                                </DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    </div>
                                </CardHeader>
                                <CardContent className="space-y-2">
                                    {depot.address && (
                                        <p className="text-sm text-muted-foreground flex items-start gap-1.5">
                                            <MapPin className="h-3.5 w-3.5 mt-0.5 shrink-0" />
                                            {depot.address}
                                        </p>
                                    )}
                                    {depot.phone && (
                                        <p className="text-sm text-muted-foreground flex items-center gap-1.5">
                                            <Phone className="h-3.5 w-3.5 shrink-0" />
                                            {depot.phone}
                                        </p>
                                    )}
                                    <div className="pt-2 border-t border-border/50">
                                        <p className="text-xs text-muted-foreground">
                                            <span className="font-semibold text-foreground">{depot.stock_count}</span> référence{Number(depot.stock_count) > 1 ? 's' : ''} en stock
                                        </p>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}
            </main>
        </div>
    )
}
